-- 已核验数据导入脚本（齐齐哈尔大学 2025 黑龙江普通本科批）
-- 核验时间：2026-04-20
-- 说明：
-- 1. 数据来源为齐齐哈尔大学招生就业处官方录取分数公告。
-- 2. 该公告给出专业组、专业、最高分、最低分、平均分，但未给出最低位次，本批统一写入 min_rank=0。
-- 3. 为避免同名专业在不同专业组或专项计划下冲突，admission_type 保留“专业组-专业名-备注”原始辨识信息。

ON CONFLICT (name, province) DO UPDATE SET
    city = EXCLUDED.city,
    level = EXCLUDED.level,
    source_name = EXCLUDED.source_name,
    source_url = EXCLUDED.source_url,
    updated_at = CURRENT_TIMESTAMP;

ON CONFLICT (college_id, province, year, subject, batch, admission_type) DO UPDATE SET
    min_score = EXCLUDED.min_score,
    avg_score = EXCLUDED.avg_score,
    max_score = EXCLUDED.max_score,
    min_rank = EXCLUDED.min_rank,
    source_name = EXCLUDED.source_name,
    source_url = EXCLUDED.source_url,
    updated_at = CURRENT_TIMESTAMP;
